 58→// OpenAI Whisper
 59→async function transcribeOpenAIWhisper(filePath: string, apiKey: string): Promise<string> {
 60→  const audioBase64 = await RNFS.readFile(filePath, 'base64');
 61→  const boundary = 'boundary' + Date.now();
 62→  const fileName = filePath.split('/').pop() || 'audio.wav';
 63→  const binaryStr = atob(audioBase64);
 64→  const bytes = new Uint8Array(binaryStr.length);
 65→  for (let i = 0; i < binaryStr.length; i++) bytes[i] = binaryStr.charCodeAt(i);
 66→
 67→  const formParts = [
 68→    `--${boundary}\r\nContent-Disposition: form-data; name="file"; filename="${fileName}"\r\nContent-Type: audio/wav\r\n\r\n`,
 69→    bytes,
 70→    `\r\n--${boundary}\r\nContent-Disposition: form-data; name="model"\r\n\r\nwhisper-1\r\n--${boundary}--\r\n`,
 71→  ];
 72→
 73→  const resp = await fetch('https://api.openai.com/v1/audio/transcriptions', {
 74→    method: 'POST',
 75→    headers: {Authorization: `Bearer ${apiKey}`, 'Content-Type': `multipart/form-data; boundary=${boundary}`},
 76→    body: new Blob(formParts),
 77→  });
 78→  const data = await resp.json();
 79→  if (data.text) return data.text;
 80→  throw new Error('Whisper识别失败: ' + JSON.stringify(data));
 81→}
