// 百度ASR获取Token
async function getBaiduToken(apiKey: string, secretKey: string): Promise<string> {
  const url = `https://aip.baidubce.com/oauth/2.0/token?grant_type=client_credentials&client_id=${apiKey}&client_secret=${secretKey}`;
  const response = await fetch(url, {
    method: 'POST',
    headers: {'Content-Type': 'application/json', 'Accept': 'application/json'}
  });
  const data = await response.json();

  if (data.error) {
    throw new Error(`百度认证失败: ${data.error_description || data.error}`);
  }
  if (!data.access_token) {
    throw new Error('百度认证失败: 未获取到access_token');
  }
  return data.access_token;
}

// 测试转写连接
export async function testAsrConnection(providerId: AsrProviderId, keyConfig: any): Promise<{ok: boolean; msg: string}> {
  try {
    if (!keyConfig?.key) return {ok: false, msg: '未填写API Key'};

    switch (providerId) {
      case 'aliyun':
        if (!keyConfig.secret || !keyConfig.appKey) return {ok: false, msg: '请填写AccessKey Secret和AppKey'};
        return {ok: true, msg: '配置格式正确，将在实际转写时验证'};

      case 'baidu':
        if (!keyConfig.secret) return {ok: false, msg: '请填写Secret Key'};
        // 实际验证百度凭据
