/**
 * Test Baidu ASR Connection
 * Tests the Baidu ASR OAuth token endpoint with provided credentials
 */

const API_KEY = 'huCUugakARRR3KVWmFF9OX1W';
const SECRET_KEY = 'BxciNXzdKDJxZkXTPdNmfyn5JLMV0QxX';

async function testBaiduConnection() {
  console.log('='.repeat(60));
  console.log('Baidu ASR Connection Test');
  console.log('='.repeat(60));
  console.log(`API Key: ${API_KEY.substring(0, 10)}...${API_KEY.substring(API_KEY.length - 4)}`);
  console.log(`Secret Key: ${SECRET_KEY.substring(0, 10)}...${SECRET_KEY.substring(SECRET_KEY.length - 4)}`);
  console.log('');

  const url = `https://aip.baidubce.com/oauth/2.0/token?grant_type=client_credentials&client_id=${API_KEY}&client_secret=${SECRET_KEY}`;

  console.log('Sending request to Baidu OAuth endpoint...');
  console.log(`URL: https://aip.baidubce.com/oauth/2.0/token`);
  console.log('');

  try {
    const response = await fetch(url, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Accept': 'application/json'
      }
    });

    console.log(`Response Status: ${response.status} ${response.statusText}`);
    const data = await response.json();
    console.log('Response Data:', JSON.stringify(data, null, 2));
    console.log('');

    if (data.error) {
      console.log('❌ FAILED');
      console.log(`Error: ${data.error}`);
      console.log(`Description: ${data.error_description || 'N/A'}`);
      return { ok: false, msg: `认证失败: ${data.error_description || data.error}` };
    }

    if (data.access_token) {
      console.log('✓ SUCCESS');
      console.log(`Access Token: ${data.access_token.substring(0, 20)}...`);
      console.log(`Token Type: ${data.token_type || 'Bearer'}`);
      console.log(`Expires In: ${data.expires_in || 'N/A'} seconds`);
      console.log('');
      console.log('The Baidu ASR credentials are valid!');
      return { ok: true, msg: '百度ASR连接成功！凭证有效' };
    }

    console.log('⚠ UNKNOWN RESPONSE');
    console.log('Response did not contain expected fields');
    return { ok: false, msg: '响应格式异常' };

  } catch (error) {
    console.log('❌ ERROR');
    console.log(`Message: ${error.message}`);
    return { ok: false, msg: `连接错误: ${error.message}` };
  }
}

// Run the test
testBaiduConnection().then(result => {
  console.log('');
  console.log('='.repeat(60));
  console.log('Final Result:');
  console.log(`  Status: ${result.ok ? '✓ PASS' : '✗ FAIL'}`);
  console.log(`  Message: ${result.msg}`);
  console.log('='.repeat(60));
  process.exit(result.ok ? 0 : 1);
});

